using sv_e82d3eabcf514c3f9c62d0fb9043d348.Models;

namespace sv_e82d3eabcf514c3f9c62d0fb9043d348.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomatoes.", 30),
            new(2, "Pasta Carbonara", "Creamy Roman pasta with guanciale, egg yolk, and Pecorino Romano.", 25),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream and cocoa.", 45),
            new(4, "Risotto alla Milanese", "Saffron-infused Arborio rice cooked slowly in broth.", 40),
        },
        [2] = new List<Recipe>
        {
            new(5, "Kung Pao Chicken", "Spicy stir-fried chicken with peanuts, vegetables, and chili peppers.", 35),
            new(6, "Mapo Tofu", "Silken tofu in a fiery Sichuan sauce with minced pork.", 20),
            new(7, "Xiaolongbao", "Delicate soup dumplings filled with pork and rich broth.", 90),
            new(8, "Char Siu", "Cantonese-style barbecue pork with a sweet and savory glaze.", 60),
        },
        [3] = new List<Recipe>
        {
            new(9, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion.", 50),
            new(10, "Mole Poblano", "Rich chocolate-chili sauce served over chicken.", 120),
            new(11, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(12, "Churros", "Fried dough pastry coated in cinnamon sugar, served with chocolate sauce.", 35),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate a slow API call
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_e82d3eabcf514c3f9c62d0fb9043d348.Models
@using sv_e82d3eabcf514c3f9c62d0fb9043d348.Services
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;

    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes =>
        Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes!.OrderByDescending(r => r.Id),
            "popular" => _recipes!.OrderBy(r => r.PrepTimeMinutes),
            _ => _recipes!
        };

    protected override async Task OnParametersSetAsync()
    {
        // Only reload data when the cuisine changes, not when sort changes
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var cancellationToken = _cts.Token;

        _error = null;

        if (_recipes is not null)
        {
            _isRefreshing = true;
        }

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cancellationToken);

            // If cancelled while awaiting, don't update state
            cancellationToken.ThrowIfCancellationRequested();

            _recipes = results;
            _loadedCuisineId = CuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
        {
            // Request was superseded or component is disposing; do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
            _isRefreshing = false;
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
            _isRefreshing = false;
        }
    }

    private async Task RetryAsync()
    {
        _error = null;
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

